window.__QUIZ_DATA__=[{"id":"objective>Computer Studies>2021>1","subject":"Computer Studies","year":"2021","type":"Objective","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"Quantitative data can exist in","images":[],"options":{"A":"continuous form only","B":"continuous and discrete forms","C":"nominal and ordinal forms","D":"ordinal form only"},"answer":"B","explanation":"Quantitative data is defined as the value of data in the form of counts or numbers where each data-set has a unique numerical value associated with it.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>2","subject":"Computer Studies","year":"2021","type":"Objective","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"Data created by the user is called","images":[],"options":{"A":"primary data","B":"qualitative data","C":"quantitative data","D":"secondary data"},"answer":"A","explanation":"Primary data is data that is collected directly from the source. It is the most original and accurate type of data.    Secondary data is data that has been collected and analyzed by someone else. It is often used to supplement primary data.    Qualitative data is data that is non-numerical and descriptive. It is often used to understand people's thoughts, feelings, and experiences.    Quantitative data is data that is numerical and can be measured. It is often used to describe and analyze trends.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>3","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The sequence of operation of a computer is","images":[],"options":{"A":"accept data, process data and produce output","B":"accept data, produce data and produce information","C":"produce data, supply data and produce output","D":"process data, produce data and display information"},"answer":"A","explanation":"At a fundamental level, computers operate through these four functions; Input, Output, Processing and Storage.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>4","subject":"Computer Studies","year":"2021","type":"Objective","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"Which of the following description is not true about data? It","images":[],"options":{"A":"can be converted to information","B":"is a collection of raw facts and figures","C":"is unorganized","D":"is used for decision making"},"answer":"D","explanation":"The statement 'data is used for decision making' is not true about data. Data in its raw form cannot be used for decision making. It is only after data has been processed into information that it can be used for decision making.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>5","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : CLASSIFICATION OF COMPUTERS","question":"Which of the following statements is true about supercomputers? They","images":[],"options":{"A":"can fit on a single small chip","B":"are easily affordable","C":"can process billions of operations in a second","D":"are found across various homes and offices"},"answer":"C","explanation":"A supercomputer is a computer that performs at or near the currently highest operational rate for computers. Supercomputers have been used for scientific and engineering applications that must handle very large database or do a great amount of computation ( or both).","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>6","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"The Slides Rule is accurate to","images":[],"options":{"A":"1-2 decimal places","B":"3 -4 decimal places","C":"5-6 decimal places","D":"6 decimal places"},"answer":"B","explanation":"The slide rule is a mechanical analog computer used primarily for multiplication and division, and also for functions such as exponents, roots, logarithm, and trigonometry, but typically not for addition or subtraction. In practice, you get between two to three significant figures from slide rule calculations, and these are errors compound as you use intermediate values in subsequent calculations.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>7","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : CLASSIFICATION OF COMPUTERS","question":"What factors will motivate a field engineer into choosing a notebook computer over a desktop computer?","images":[],"options":{"A":"Cost, convenience and battery life","B":"Cost, size and convenience","C":"Size, convenience and battery life","D":"Size, cost and battery life"},"answer":"C","explanation":"The factors that will motivate a field engineer into choosing a notebook computer over a desktop computer are: The Size, convenience and battery life.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>8","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"A collection of wires through which data are transmitted from one part of the computer to another is known as","images":[],"options":{"A":"address","B":"bus","C":"driver","D":"register"},"answer":"B","explanation":"In computer architecture, a bus is a communication system that transfers data between components inside a computer, or between computers.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>9","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The total possible combination of the input variables for a logic gate containing three input variables is","images":[],"options":{"A":"3","B":"4","C":"8","D":"12"},"answer":"C","explanation":"With three total inputs, you can make 8 ie  2n where n is the number of inputs.   Therefore, 2^ (3) = 2 x 2 x 2  = 8","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>10","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"What is the the least number of 750 MB capacity CD-ROM discs needed to transfer 10 GB size file?","images":[],"options":{"A":"75","B":"31","C":"14","D":"13"},"answer":"C","explanation":"1000 megabytes = 1 Gigabyte   Tota megabytes = 1000 x 10  = 10000   Therefore, 750MB = 10,000/750   = 13.33","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>11","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"- The logic gate represented in the diagram is called","images":["data:image/png;base64,"],"options":{"A":"AND gate","B":"NAND gate","C":"NOR gate","D":"OR gate"},"answer":"B","explanation":"a NAND gate is a logic gate which produces an output which is false only if all its inputs are true; thus its output is complement to that of an AND gate. It is a two input digital combination logic circuit that performs the logical inverse of AND gate.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>12","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"Use the logic gate in the diagram to answer this question       - Which of the logic gates will give an output opposite to the input state?","images":["data:image/png;base64,"],"options":{"A":"X","B":"Y and Z","C":"Z","D":"X and Y"},"answer":"A","explanation":"The diagram X represent the NOT gate. The NOT gate is the simplest and it is also known as inverter. It accepts a single input and outputs the opposite value. If the input is 0, the output is 1 and if the input is 1, the output is 0.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>13","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"Use the logic gate in the diagram to answer this question     - Which of the following statements is true about the logic gates X and Y?","images":["data:image/png;base64,"],"options":{"A":"They both have multiple output variable","B":"The output state of each depends on the inputs state","C":"The output is true only if all inputs are true","D":"They are both equivalent gates"},"answer":"B","explanation":"Computers use Logic gates to transform the 1s and 0s from input wires. A logic gate accepts inputs and then output a result on their state.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>14","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"- The logic equation of the logic circuit in the above diagram is","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"B","explanation":"From the truth table, The Logical equation for the logic circuit is Z = A +B. C","marks":"1","difficulty":"3"},{"id":"objective>Computer Studies>2021>15","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The operation of a computer and peripherals attached to it is controlled by","images":[],"options":{"A":"application software","B":"hardware","C":"live ware","D":"system software"},"answer":"D","explanation":"The operation of a computer and peripherals attached to it is controlled by the system software. System software is a type of computer program that is designed to run a computer's hardware and application programs. It includes the operating system and device drivers that control how the hardware interfaces with the software.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>16","subject":"Computer Studies","year":"2021","type":"Objective","topic":"INFORMATION AGE : HISTORY OF COMPUTERS","question":"COBOL was developed for","images":[],"options":{"A":"business operations","B":"game developers","C":"mobile applications developers","D":"search engine optimization"},"answer":"A","explanation":"COBOL meaning Common business oriented language , is a compiled English-like computer programming language designed for business use. It is primarily used in business, finance, and administrative system for companies and governments.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>17","subject":"Computer Studies","year":"2021","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM","question":"The operating system performs the following operations except","images":[],"options":{"A":"organization of data","B":"resource allocation","C":"creation of data","D":"arrangement of files"},"answer":"C","explanation":"An operating system has three main functions:   - manage the computer's resources such as the central processing unit, memory, disk drives and printers   - establish a user interface   - execute and provide services for applications software.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>18","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The fundamental purpose of the BIOS is","images":[],"options":{"A":"initializing and testing hardware components","B":"testing the system performance","C":"updating the system performance","D":"saving the operating system's life"},"answer":"A","explanation":"BIOS (Basic Input / Output System), computer program that is typically stored in EPROM and used by the CPU to perform start-up procedures when the computer is turned on. Its two major procedures are determining what peripheral devices (keyboard, mouse, disk drives, printers, video cards etc) are available and loading the operating system into main memory.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>19","subject":"Computer Studies","year":"2021","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM","question":"The IF.....THEN statement in BASIC is called","images":[],"options":{"A":"an assignment statement","B":"an object","C":"a class","D":"a control structure"},"answer":"D","explanation":"The IF....THEN.....ELSELF.....ELSE control flow statement allows identifying if a certain condition is true, and executes a block of code if it is the case.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>20","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"The use of natural language and symbols to write instructions for the computer is called","images":[],"options":{"A":"machine language programming","B":"assembly language programming","C":"algorithm language programming","D":"high level language programming"},"answer":"D","explanation":"A high level language is a programming language such as C, FORTRAN, or Pascal that enables a programmer to write programs that are more or less independent of a particular type of computer.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>21","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"Which of the following stages of the SDLC is post operational stage?","images":[],"options":{"A":"Analysis","B":"Design","C":"Investigation","D":"Maintenance"},"answer":"D","explanation":"The objective of the Post-Implementation Phase is to maintain and enhance the system to meet the ongoing needs of the user community. The operations and maintenance phase is the last phase when end users can fine tune the system, if they wish, to boost performance, add new capabilities or meet additional user requirements.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>22","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"The expression 5 + 3* 4/2 - 3^2 in QBASIC evaluate to","images":[],"options":{"A":"7","B":"4","C":"2","D":"1"},"answer":"C","explanation":"Operator\tName\t^\tExponent\t*\tMultiplication\t/\tDivision\t+\tAddition\t-\tSubtraction & Unary Minus\t(....)\tSub expression\t    Therefore, 5 + 3* 4/2 - 32   = 5 + 3* 4/2 - 9   = 5 + 3* 2 - 9   = 5 + 6 - 9   = 11 - 9   = 2","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>23","subject":"Computer Studies","year":"2021","type":"Objective","topic":"INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING","question":"Use diagram below to answer question      - The basic problem with the flowchart is that it has","images":["data:image/jpeg;base64,"],"options":{"A":"no direction","B":"no algorithm","C":"END as a process","D":"improper branch out"},"answer":"D","explanation":"From the diagram above, the basic problem is the improper branch out.","marks":"1","difficulty":"3"},{"id":"objective>Computer Studies>2021>24","subject":"Computer Studies","year":"2021","type":"Objective","topic":"INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING","question":"Use diagram below to answer question    - What activity is the flowchart made to represent","images":["data:image/jpeg;base64,"],"options":{"A":"How to pick an orange","B":"Instruction to pick an orange","C":"Evaluation on how to pick an orange","D":"Number of times to pick an orange"},"answer":"B","explanation":"A flow chart is a type of diagram that represents a workflow or process. The flowchart shows the steps as boxes of various kinds, and their order by connecting the boxes with arrows.","marks":"1","difficulty":"3"},{"id":"objective>Computer Studies>2021>25","subject":"Computer Studies","year":"2021","type":"Objective","topic":"INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING","question":"Use diagram below to answer question    - If N in the flowchart is represented by 10, which of the following conditions is not true?","images":["data:image/jpeg;base64,"],"options":{"A":"If C > 10, do not pick orange","B":"If C = 10, stop picking orange","C":"If C","D":"If C = 10, continue picking orange"},"answer":"C","explanation":"Since the N is a Rhombus, then it has one or several entrance point and exactlty two outputs. It contains a valid conditional expression. The expression could be evaluated as \"true of \"false\".","marks":"1","difficulty":"3"},{"id":"objective>Computer Studies>2021>26","subject":"Computer Studies","year":"2021","type":"Objective","topic":"INFORMATION TRANSMISSION : NETWORKING","question":"A computer system on the network that stores pages , takes requests from clients as well as send out information is called a","images":[],"options":{"A":"client","B":"web page","C":"web server","D":"website"},"answer":"C","explanation":"A web server is software and hardware that uses HTTP and other protocols to respond to client requests made over the World Wide Web.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>27","subject":"Computer Studies","year":"2021","type":"Objective","topic":"INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION","question":"The device in Figure 5 uses a transmission method called","images":["data:image/png;base64,"],"options":{"A":"broadcast","B":"podcast","C":"multicast","D":"unicast"},"answer":"A","explanation":"Broadcasting is a method of transferring a message to all recipents simultaneously.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>28","subject":"Computer Studies","year":"2021","type":"Objective","topic":"INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION","question":"In the diagram, the signal from modem X to modem Y is","images":["data:image/png;base64,"],"options":{"A":"analogue","B":"digital","C":"imaginary","D":"aperiodic"},"answer":"A","explanation":"Analogue signals are transmitted using a continuously changing quantity as a reference. An example of an analogue signal is the transmission of radio, waves, television waves or sound waves.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>29","subject":"Computer Studies","year":"2021","type":"Objective","topic":"INFORMATION TRANSMISSION : INTERNET","question":"The \"/exams\" in the web address: https://www.waec.org.ng/exams is called","images":[],"options":{"A":"domain name","B":"path","C":"port","D":"subdomain"},"answer":"B","explanation":"A path is a string of character used to uniquely identify a location in a directory structure. It is used to represent the directory/file relationships common in modern operating systems and are essential in the construction of uniform Resource Locators","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>30","subject":"Computer Studies","year":"2021","type":"Objective","topic":"INFORMATION TRANSMISSION : INTERNET","question":"Which of the following statements about URL is true? It is","images":[],"options":{"A":"a computer software program","B":"a type of web server","C":"an acronym for unlimited resources for learning","D":"the address of a document or \"page\" on the world wide web"},"answer":"D","explanation":"URL stands for Uniform Resource Locator. A URL is nothing more than the address of a given unique resource on the Web.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>31","subject":"Computer Studies","year":"2021","type":"Objective","topic":"INFORMATION TRANSMISSION : NETWORKING","question":"The type of network represented in diagram is called","images":["data:image/png;base64,"],"options":{"A":"LAN","B":"MAN","C":"PAN","D":"WAN"},"answer":"A","explanation":"LAN means Local Area Network and is a computer that interconnects computers within a limited area such as residence, school, laboratory, university campus or office building.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>32","subject":"Computer Studies","year":"2021","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : SPREADSHEET","question":"In MS Excel, the cell that contains the pointer cursor is called the","images":[],"options":{"A":"active cell","B":"current cell","C":"default cell","D":"passive cell"},"answer":"A","explanation":"The active cell is also referred to as a cell pointer or selected cell. An active cell refers to a cell in an Excel spreadsheet that is currenlty selected by clicking the mouse pointer or keyboard keys.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>33","subject":"Computer Studies","year":"2021","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES","question":"The part of the graphic interface in Figure 8 labelled V is called","images":["data:image/png;base64,"],"options":{"A":"pan","B":"zoom in","C":"zoom out","D":"fit to window"},"answer":"D","explanation":"The part of the graphic interface in Figure 8 labelled V is called fit to window.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>34","subject":"Computer Studies","year":"2021","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING","question":"The diagram above, in the number 11012 is indicated in MS Word using a feature called","images":["data:image/png;base64,"],"options":{"A":"superscript","B":"subscript","C":"root","D":"exponentiation"},"answer":"B","explanation":"In computer programming, a subscript is a number representing an element in an array. For example, with example [3] or $example[3], the [3] is the subscript of the \"example\" array.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>35","subject":"Computer Studies","year":"2021","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM","question":"The part of the MS Access interface labeled X,  is called","images":["data:image/png;base64,"],"options":{"A":"Report view","B":"Report wizard","C":"Query design","D":"Query view"},"answer":"D","explanation":"It shows a select query is a database object that shows information's in Datasheet view. It does not store data; it displays data that is stored in tables.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>36","subject":"Computer Studies","year":"2021","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : SPREADSHEET","question":"Which of the following formulas will display the current seconds past the minute of the clock in MS Excel?","images":[],"options":{"A":"= MINUTE0","B":"= MINUTE (N0W0)","C":"= MINUTE (YEAR0)","D":"= MINUTE (HOUR(N0W0))"},"answer":"B","explanation":"the current seconds past the minute of the clock in MS Excel is shown as = MINUTE(N0W0)","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>37","subject":"Computer Studies","year":"2021","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING","question":"The part of the MS Word interface labeled II  is called","images":["data:image/png;base64,"],"options":{"A":"Read mode","B":"Print Layout","C":"Proofing error","D":"Web layout"},"answer":"B","explanation":"The print view is located at the bottom-right corner of your document window. Click view tab and then click the view you want to use, such as print layout or draft view.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>38","subject":"Computer Studies","year":"2021","type":"Objective","topic":"DATA MANAGEMENT : RELATIONAL MODEL","question":"What type of relationship can you deduce from the statement a department has many employees?","images":[],"options":{"A":"One-to-one","B":"One-to-many","C":"Many-to-many","D":"Many-to-one"},"answer":"B","explanation":"In a relational database, a one-to-many relationship exists when one row in table A may be linked with many rows in table B, but one row in table B is linked to only one row in table A.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>39","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The screen background where icons and windows are displayed in GUI is called","images":[],"options":{"A":"explorer","B":"desktop","C":"opening screen","D":"home page"},"answer":"B","explanation":"The desktop is the main screen area that you see after you turn on your computer and log on to Windows. The desktop is sometimes defined more broadly to include the taskbar and Windows Sidebar. The taskbar sits at the bottom of your screen. It shows you which programs are running and allows you to switch between them.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>40","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"The windows shortcut key for closing an active application is","images":[],"options":{"A":"Alt +F4","B":"Ctrl + Alt +Del","C":"Ctrl +Esc","D":"Ctrl + Shift +Del"},"answer":"A","explanation":"The shortcut key for closing an active application in Windows is 'Alt + F4'. This command sends a close message to the active window, which will usually result in the application closing. 'Ctrl + Alt + Del' is used to open the task manager, 'Ctrl + Esc' opens the start menu, and 'Ctrl + Shift + Del' opens the clear browsing data window in most browsers.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>41","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"Changing the default settings or appearance of the Taskbar in windows by a user is known as","images":[],"options":{"A":"customization","B":"designing","C":"generalization","D":"globalization      ."},"answer":"A","explanation":"Customization lets users make their own selections about what they want to see, or set preferences for how information is organized or displayed. It can enhance user experience because it allows users to control their interaction","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>42","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The part of the computer system shown is used to","images":["data:image/png;base64,"],"options":{"A":"perform memory test","B":"power on or off the computer","C":"print a document from the computer","D":"reset the computer to factory setting"},"answer":"B","explanation":"In a typical desktop computer setup, power buttons and switches appear on the front and sometimes back of the monitor and on the front and back of the case.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>43","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"A single character in an EBCDIC encoding system can be represented using","images":[],"options":{"A":"4 bits","B":"6 bits","C":"8 bits","D":"16 bits"},"answer":"C","explanation":"Extended Binary Coded Decimal interchange Code is an eight-bit character encoding used mainly on IBM mainframe and IBM midrange computer operating systems.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>44","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"Evaluate 100112 - 11112","images":[],"options":{"A":"000102","B":"1002","C":"010002","D":"100002"},"answer":"B","explanation":"100112 - 11112   = 001002     Alternatively:   Convert 100112 to base to   1 x 24 + 1 x21 + 1 x 20   = 16 + 2 + 1   = 1910     11112 = 1 x 23 + 1 x2 2 + 1 x 21 + 1 x 20   = 8+4+2+1   = 1510     Therefore, 19 - 15 = 4   Convert 410 to base 2    2\t4\t2\t2 R 0\t2\t1 R 0\t\t0 R 1\t           410 = 1002","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>45","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The binary number 0.1101 in decimal is","images":[],"options":{"A":"0.8125","B":"0.8215","C":"0.8225","D":"0.8512"},"answer":"A","explanation":"0.1101 = 1 x 2-1 + 1 x 2-2 + 1 x2 -3 + 1 x 2-4   = 1/2 + 1/4 + 0 + 1/16   = 13/16   = 0.812510","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>46","subject":"Computer Studies","year":"2021","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER","question":"To prevent unforeseen data loss, a user must","images":[],"options":{"A":"edit the data","B":"create the data","C":"backup the data","D":"defragment the data"},"answer":"C","explanation":"Ways to prevent data loss are: Always back up your data, Diversify your backups, Encrypt sensitive data, Address data security etc.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2021>47","subject":"Computer Studies","year":"2021","type":"Objective","topic":"DATA MANAGEMENT : FILE ORGANIZATION","question":"The file access method shown is called","images":["data:image/png;base64,"],"options":{"A":"hashed access","B":"indexed access","C":"random access","D":"sequential access"},"answer":"B","explanation":"Index sequential method is built on the top of the sequential access method. These methods construct an index for the file. The index, like an index in the back of a book, contains the pointer to the various blocks.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>48","subject":"Computer Studies","year":"2021","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"Which of the following options is not a similarity between computer file and manual file? Both can","images":[],"options":{"A":"be accessed","B":"be retrieved","C":"store multimedia","D":"contain information"},"answer":"C","explanation":"Both computer files and manual files can be accessed, retrieved, and contain information. However, manual files cannot store multimedia. Multimedia files are digital or electronic files that contain audio, video, or both. They can be played, displayed, or executed on a computer or electronic device.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>49","subject":"Computer Studies","year":"2021","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : COMPUTER VIRUS","question":"A computer program that gathers information about a person or organization without their knowledge or consent is known as","images":[],"options":{"A":"adware","B":"time bomb","C":"trojan horse","D":"spyware"},"answer":"D","explanation":"Spyware is software with malicious behaviour that aims to gather information about a person or organization and send it to another entity in a way that harms the user.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2021>50","subject":"Computer Studies","year":"2021","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : COMPUTER VIRUS","question":"The following actions are the effects of virus infection in a system except","images":[],"options":{"A":"deletion of files","B":"slow operation","C":"hard disk failure","D":"display of unwanted message"},"answer":"C","explanation":"Computer viruses infect personal computers (PCs) and server. Some viruses create mere annoyance, but other can do serious damage: delete or change files, steal important information, load and run unwanted applications, send documents via electronic mail or even cripple a machines operating system","marks":"1","difficulty":"2"}];